    private fun handleLocalStorageRequest(requestId: String?, data: String?) {
        try {
            val request = gson.fromJson(data, JsonObject::class.java)
            val operation = request.get("operation")?.asString
            val key = request.get("key")?.asString
            val value = request.get("value")?.toString()

            val result = when (operation) {
                "setItem" -> {
                    val prefs = context.getSharedPreferences("web_storage", Context.MODE_PRIVATE)
                    prefs.edit().putString(key, value).apply()
                    gson.toJson(mapOf("success" to true))
                }
                "getItem" -> {
                    val prefs = context.getSharedPreferences("web_storage", Context.MODE_PRIVATE)
                    val storedValue = prefs.getString(key, null)
                    gson.toJson(mapOf("success" to true, "value" to storedValue))
                }
                "removeItem" -> {
                    val prefs = context.getSharedPreferences("web_storage", Context.MODE_PRIVATE)
                    prefs.edit().remove(key).apply()
                    gson.toJson(mapOf("success" to true))
                }
                else -> gson.toJson(mapOf("error" to "Invalid operation"))
            }

            webView.post { webView.loadUrl("javascript:handleNativeResponse('$requestId', '$result')") }
        } catch (e: Exception) {
            val errorResult = gson.toJson(mapOf("error" to e.message))
            webView.post { webView.loadUrl("javascript:handleNativeResponse('$requestId', '$errorResult')") }
        }
    }

